import React, { useMemo, useState } from 'react';
import { Card, Badge, Button } from 'react-bootstrap';
import { AlertTriangle, Clock3, CheckCircle, RefreshCcw } from 'lucide-react';
import './ExpiryTracking.css';

// Helper to compute days left from an ISO date string
const getDaysLeft = (expiryDate) => {
  if (!expiryDate) return null;
  const today = new Date();
  const expiry = new Date(expiryDate);
  const diffTime = expiry.setHours(0, 0, 0, 0) - today.setHours(0, 0, 0, 0);
  return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
};

// Categorize based on days left
const getCategory = (daysLeft) => {
  if (daysLeft === null) return 'others';
  if (daysLeft <= 0) return 'expired';
  if (daysLeft <= 5) return 'expiring_1_5';
  if (daysLeft <= 30) return 'expiring_6_30';
  return 'others';
};

const ExpiryTracking = () => {
  const [filter, setFilter] = useState('all');

  // Demo dataset
  const documents = useMemo(
    () => [
      {
        id: 'DOC038',
        fileName: 'EMP002_documantation1_20251213_112505.docx',
        employeeName: 'Priya Singh',
        employeeId: 'EMP002',
        type: 'Employment Contract',
        expiryDate: '2025-12-13',
      },
      {
        id: 'DOC001',
        fileName: 'EMP001_consolidated_1_20251209_162820.pdf',
        employeeName: 'Rajesh Kumar',
        employeeId: 'EMP001',
        type: 'ID Proof',
        expiryDate: '2025-12-15',
      },
      {
        id: 'DOC006',
        fileName: 'EMP001_provisional_20251209_153120.pdf',
        employeeName: 'Rajesh Kumar',
        employeeId: 'EMP001',
        type: 'Educational Certificate',
        expiryDate: '2025-12-15',
      },
      {
        id: 'DOC011',
        fileName:
          'EMP005_Data_Analytics_Essentials_certificate_sivaranjani8930-gmail-com_78988dc5-0117-49d8-acfb-984ad8c7624c_1_20251209_203227.pdf',
        employeeName: 'Vikram Sharma',
        employeeId: 'EMP005',
        type: 'Training Certificate',
        expiryDate: '2025-12-15',
      },
      {
        id: 'DOC016',
        fileName: 'EMP002_Screenshot_2025-10-07_192803_20251209_214857.png',
        employeeName: 'Priya Singh',
        employeeId: 'EMP002',
        type: 'ID Proof',
        expiryDate: '2025-12-15',
      },
      {
        id: 'DOC030',
        fileName: 'EMP010_Contract_Letter_Rajesh_Kumar_2_20251212_140302.pdf',
        employeeName: 'Meera Nair',
        employeeId: 'EMP010',
        type: 'Employment Contract',
        expiryDate: '2025-12-15',
      },
      {
        id: 'DOC002',
        fileName: 'EMP001_shivas_resume_20251208_113523.pdf',
        employeeName: 'Rajesh Kumar',
        employeeId: 'EMP001',
        type: 'Employment Contract',
        expiryDate: '2025-12-20',
      },
      {
        id: 'DOC007',
        fileName: 'EMP001_10th_20251209_153120.pdf',
        employeeName: 'Rajesh Kumar',
        employeeId: 'EMP001',
        type: 'Educational Certificate',
        expiryDate: '2025-12-20',
      },
      {
        id: 'DOC050',
        fileName: 'EMP003_generic_doc.pdf',
        employeeName: 'Amit Patel',
        employeeId: 'EMP003',
        type: 'ID Proof',
        expiryDate: '2026-02-10',
      },
    ],
    []
  );

  const enrichedDocs = useMemo(
    () =>
      documents.map((doc) => {
        const daysLeft = getDaysLeft(doc.expiryDate);
        return {
          ...doc,
          daysLeft,
          category: getCategory(daysLeft),
        };
      }),
    [documents]
  );

  const metrics = useMemo(() => {
    const base = {
      expired: 0,
      expiring_1_5: 0,
      expiring_6_30: 0,
      others: 0,
      total: enrichedDocs.length,
    };
    enrichedDocs.forEach((doc) => {
      base[doc.category] = (base[doc.category] || 0) + 1;
    });
    return base;
  }, [enrichedDocs]);

  const filteredDocs = useMemo(() => {
    if (filter === 'all') return enrichedDocs;
    return enrichedDocs.filter((doc) => doc.category === filter);
  }, [filter, enrichedDocs]);

  const getStatusBadge = (doc) => {
    switch (doc.category) {
      case 'expired':
        return <Badge bg="danger">Expired</Badge>;
      case 'expiring_1_5':
        return <Badge bg="warning" text="dark">Critical - {doc.daysLeft} days</Badge>;
      case 'expiring_6_30':
        return <Badge bg="info" text="dark">Warning - {doc.daysLeft} days</Badge>;
      default:
        return <Badge bg="secondary">OK</Badge>;
    }
  };

  const cardConfig = [
    {
      id: 'expired',
      title: 'Expired',
      value: metrics.expired,
      subtitle: 'Requires immediate action',
      gradient: 'expired',
      icon: <AlertTriangle size={26} />,
    },
    {
      id: 'expiring_1_5',
      title: 'Expiring (1-5 Days)',
      value: metrics.expiring_1_5,
      subtitle: 'Critical alert window',
      gradient: 'critical',
      icon: <Clock3 size={26} />,
    },
    {
      id: 'expiring_6_30',
      title: 'Expiring (6-30 Days)',
      value: metrics.expiring_6_30,
      subtitle: 'Upcoming renewals',
      gradient: 'upcoming',
      icon: <Clock3 size={26} />,
    },
    {
      id: 'all',
      title: 'Total Monitored',
      value: metrics.total,
      subtitle: 'Documents tracked',
      gradient: 'total',
      icon: <CheckCircle size={26} />,
    },
  ];

  const activeFilterLabel = {
    all: 'All documents',
    expired: 'Expired documents',
    expiring_1_5: 'Expiring within 1-5 days',
    expiring_6_30: 'Expiring within 6-30 days',
  }[filter];

  return (
    <div className="expiry-tracking">
      <Card className="expiry-card mb-4">
        <Card.Body className="d-flex align-items-center justify-content-between">
          <div>
            <h3 className="mb-1 d-flex align-items-center gap-2">
              <Clock3 size={26} /> Expiry Tracking System
            </h3>
            <p className="text-muted mb-0">
              Monitor and manage document expiry dates with automated alerts
            </p>
          </div>
          <Button
            variant="light"
            className="refresh-btn"
            onClick={() => setFilter('all')}
          >
            <RefreshCcw size={18} className="me-2" />
            Reset Filters
          </Button>
        </Card.Body>
      </Card>

      <div className="row g-3 mb-4">
        {cardConfig.map((card) => (
          <div key={card.id} className="col-md-3">
            <Card
              className={`metric-card metric-${card.gradient} ${
                filter === card.id ? 'active' : ''
              }`}
              onClick={() => setFilter(card.id)}
            >
              <Card.Body>
                <div className="d-flex justify-content-between align-items-start">
                  <div>
                    <p className="text-muted mb-1">{card.title.toUpperCase()}</p>
                    <h2 className="mb-1">{card.value}</h2>
                    <small className="text-muted">{card.subtitle}</small>
                  </div>
                  <div className="metric-icon">{card.icon}</div>
                </div>
              </Card.Body>
            </Card>
          </div>
        ))}
      </div>

      <Card className="table-card">
        <Card.Header className="d-flex justify-content-between align-items-center">
          <div>
            <h5 className="mb-0">Expiry Tracking & Notifications</h5>
            <small className="text-muted">{activeFilterLabel}</small>
          </div>
          <Badge bg="secondary" pill>
            {filteredDocs.length} items
          </Badge>
        </Card.Header>
        <Card.Body className="p-0">
          <div className="table-responsive">
            <table className="table table-hover mb-0 expiry-table">
              <thead>
                <tr>
                  <th>Document</th>
                  <th>Employee</th>
                  <th>Type</th>
                  <th>Expiry Date</th>
                  <th>Days Left</th>
                  <th>Status</th>
                </tr>
              </thead>
              <tbody>
                {filteredDocs.length === 0 ? (
                  <tr>
                    <td colSpan="6" className="text-center py-4 text-muted">
                      No records for this filter.
                    </td>
                  </tr>
                ) : (
                  filteredDocs.map((doc) => (
                    <tr key={doc.id} className={`row-${doc.category}`}>
                      <td>
                        <div className="fw-semibold">{doc.id}</div>
                        <div className="text-muted small">{doc.fileName}</div>
                      </td>
                      <td>
                        <div className="fw-semibold">{doc.employeeName}</div>
                        <div className="text-muted small">{doc.employeeId}</div>
                      </td>
                      <td>{doc.type}</td>
                      <td>{doc.expiryDate}</td>
                      <td className="fw-semibold">
                        {doc.daysLeft === null
                          ? 'N/A'
                          : doc.daysLeft <= 0
                          ? 'Expires Today'
                          : `${doc.daysLeft} days`}
                      </td>
                      <td>{getStatusBadge(doc)}</td>
                    </tr>
                  ))
                )}
              </tbody>
            </table>
          </div>
        </Card.Body>
      </Card>
    </div>
  );
};

export default ExpiryTracking;
